# Remove leading Attribute lines from .cls and .bas files in all subdirectories

$dirs = Get-ChildItem "c:\database_migration\Automations\access_vba_exports" -Directory; $totalCls = 0; $totalBas = 0; foreach ($dir in $dirs) { Write-Host "Processing $($dir.Name)..." -ForegroundColor Cyan; $clsFiles = Get-ChildItem "$($dir.FullName)\*.cls" -ErrorAction SilentlyContinue; foreach ($f in $clsFiles) { $content = Get-Content $f.FullName -Raw; $lines = $content -split "`r?`n"; $startIndex = 0; for ($i = 0; $i -lt $lines.Count; $i++) { if ($lines[$i] -match '^Option (Compare|Explicit)') { $startIndex = $i; break } }; $newContent = $lines[$startIndex..($lines.Count-1)] -join "`r`n"; Set-Content $f.FullName -Value $newContent -NoNewline }; $basFiles = Get-ChildItem "$($dir.FullName)\*.bas" -ErrorAction SilentlyContinue; foreach ($f in $basFiles) { $content = Get-Content $f.FullName -Raw; $lines = $content -split "`r?`n"; $startIndex = 0; for ($i = 0; $i -lt $lines.Count; $i++) { if ($lines[$i] -match '^Option (Compare|Explicit)') { $startIndex = $i; break } }; if ($startIndex -gt 0) { $newContent = $lines[$startIndex..($lines.Count-1)] -join "`r`n"; Set-Content $f.FullName -Value $newContent -NoNewline } }; Write-Host "  Cleaned $($clsFiles.Count) .cls and $($basFiles.Count) .bas files" -ForegroundColor Green; $totalCls += $clsFiles.Count; $totalBas += $basFiles.Count }; Write-Host "`nTotal: $totalCls .cls files and $totalBas .bas files cleaned across $($dirs.Count) directories" -ForegroundColor Yellow